import (
	"container/heap"
	"math"
)

type State struct {
	node  int64
	used  int
	cost  int64
	index int
}

type PriorityQueue []*State

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
	pq[i].index = i
	pq[j].index = j
}

func (pq *PriorityQueue) Push(x interface{}) {
	n := len(*pq)
	item := x.(*State)
	item.index = n
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	item.index = -1
	*pq = old[0 : n-1]
	return item
}

func solve(n int64, edges [][]int64) int64 {
	nn := int(n)
	graph_regular := make([][][2]int64, nn)
	graph_incoming := make([][][2]int64, nn)

	for _, edge := range edges {
		u, v, w := edge[0], edge[1], edge[2]
		ui, vi := int(u), int(v)
		graph_regular[ui] = append(graph_regular[ui], [2]int64{v, w})
		graph_incoming[vi] = append(graph_incoming[vi], [2]int64{u, w})
	}

	INF := int64(math.MaxInt64)
	dist := make([][]int64, nn)
	for i := range dist {
		dist[i] = make([]int64, 2)
		dist[i][0] = INF
		dist[i][1] = INF
	}
	dist[0][0] = 0

	pq := make(PriorityQueue, 0)
	heap.Push(&pq, &State{node: 0, used: 0, cost: 0})

	for pq.Len() > 0 {
		state := heap.Pop(&pq).(*State)
		u := int(state.node)
		used := state.used
		cost := state.cost

		if cost != dist[u][used] {
			continue
		}

		for _, neighbor := range graph_regular[u] {
			v := int(neighbor[0])
			w := neighbor[1]
			newCost := cost + w
			if newCost < dist[v][0] {
				dist[v][0] = newCost
				heap.Push(&pq, &State{node: int64(v), used: 0, cost: newCost})
			}
		}

		if used == 0 {
			for _, incEdge := range graph_incoming[u] {
				v := int(incEdge[0])
				w := incEdge[1]
				newCost := cost + 2 * w
				if newCost < dist[v][0] {
					dist[v][0] = newCost
					heap.Push(&pq, &State{node: int64(v), used: 0, cost: newCost})
				}
			}
		}
	}

	endNode := nn - 1
	ans := min(dist[endNode][0], dist[endNode][1])
	if ans == INF {
		return -1
	}
	return ans
}

func min(a, b int64) int64 {
	if a < b {
		return a
	}
	return b
}
```

### Explanation
1. **Graph Representation**:
   - `graph_regular` stores outgoing edges for each node in their original direction.
   - `graph_incoming` stores edges that can be reversed from other nodes to the current node.
2. **Dijkstra's Setup**:
   - Initialize distance arrays for each node's two states (switch used or not) to `INF`.
   - Priority queue starts at node `0` in state `0` with cost `0`.
3. **Processing States**:
   - For each node-state pair, regular outgoing edges are traversed to neighbor nodes in state `0`.
   - If the node's switch is unused (state `0`), incoming edges can be reversed to traverse to neighbor nodes in state `0` at twice the cost.
4. **Result Extraction**:
   - The minimum cost to reach node `n-1` in either state is returned. If unreachable, returns `-1`.

This approach efficiently explores all possible paths while respecting the constraints of using each node's switch at most once, leveraging Dijkstra's algorithm for optimal pathfinding in the expanded state graph.

