import (
	"container/heap"
	"math"
)

type Edge struct {
	to     int
	weight int64
}

type Item struct {
	node int
	cost int64
	index int
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
	pq[i].index = i
	pq[j].index = j
}

func (pq *PriorityQueue) Push(x interface{}) {
	n := len(*pq)
	item := x.(*Item)
	item.index = n
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	item.index = -1
	*pq = old[0 : n-1]
	return item
}

func solve(nParam int64, edgesParam [][]int64) int64 {
	n := int(nParam)
	graph := make([][]Edge, 2*n)
	inEdges := make([][]Edge, n)

	for i := range inEdges {
		inEdges[i] = make([]Edge, 0)
	}

	for _, e := range edgesParam {
		u := int(e[0])
		v := int(e[1])
		w := e[2]
		graph[u] = append(graph[u], Edge{v, w})
		graph[u+n] = append(graph[u+n], Edge{v + n, w})
		inEdges[v] = append(inEdges[v], Edge{u, w})
	}

	for v := 0; v < n; v++ {
		for _, e := range inEdges[v] {
			graph[v] = append(graph[v], Edge{e.to + n, 2 * e.weight})
		}
	}

	dist := make([]int64, 2*n)
	for i := range dist {
		dist[i] = math.MaxInt64
	}
	dist[0] = 0

	pq := make(PriorityQueue, 0)
	heap.Push(&pq, &Item{node: 0, cost: 0})

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*Item)
		u := item.node
		if item.cost != dist[u] {
			continue
		}
		for _, edge := range graph[u] {
			v := edge.to
			w := edge.weight
			newCost := dist[u] + w
			if newCost < dist[v] {
				dist[v] = newCost
				heap.Push(&pq, &Item{node: v, cost: newCost})
			}
		}
	}

	res := min(dist[n-1], dist[2*n-1])
	if res == math.MaxInt64 {
		return -1
	}
	return res
}

func min(a, b int64) int64 {
	if a < b {
		return a
	}
	return b
}
